var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"수고하셨습니다. 스승님.","JPN":"お疲れ様でした、師匠。","ENG":"Good work. Master.","TWN":"辛苦妳了，師父。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"전투 보고서는 본사 귀환 후에 받기로 하죠.","JPN":"戦闘報告書は本社帰還後に提出して頂きますね。","ENG":"You can debrief me once we get back to corporate HQ.","TWN":"戰鬥報告會在回總公司後收取。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"확보한 로스트 쉽의 관리는 임시로 알트 소대에게 맡기도록 하겠습니다.","JPN":"確保したロストシップの管理は、まずはアルト小隊に任せようと思います。","ENG":"For the time being, I’ll task the ALT Squad to look after the Lost Ship we secured.","TWN":"已確保的失落艦船將由阿爾特小隊臨時負責管理。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"어차피 실비아 양이 곧 본국에서 관리할 인원들을 데려올 테니 우리 쪽에서 신경 쓸 건 얼마 없을.......","JPN":"シルビアさんがまもなく本国の管理スタッフを連れてきますから、こちらで気にすることはあまりない……","ENG":"Besides, Sylvia will be bringing her agents from stateside to take it off our hands soon, so we won’t really need to-","TWN":"反正希爾維亞小姐很快就會把管理人員帶到本國，我們也不用太操心。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"언제까지 모른 척하고만 있을 거야, 대체!!","JPN":"いったい、いつまでしらばくれるつもりなんだ！","ENG":"How long are you going to play dumb with me?!","TWN":"妳要裝傻到什麼時候！ "},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"나유빈이 살아 있다고!","JPN":"イチノセ・カオルが生きているんだ！","ENG":"Na Yubin is alive!","TWN":"羅瑜斌還活著？！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"그 오랜 세월 동안, 그 녀석이 살아 있다는 소리는 한 번도 한 적이 없었잖아?!","JPN":"これまで長い間、あいつが生きているという話は一度も聞いてないぞ！？","ENG":"You never once mentioned he’s still alive after all this time!","TWN":"這麼多年以來，妳一次都沒跟我說他還活著吧？！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"대체 뭘 숨기고 있었던 거야? 그 녀석은 또 무슨 꿍꿍이고?!","JPN":"いったい何を隠していたんだ？　それに、あいつはまた何を企んでいる？","ENG":"What were you trying to hide? And what’s he up to?!","TWN":"妳到底在隱瞞什麼？那傢伙又在搞什麼鬼？！"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이건 정말 말도 안 되는.....","JPN":"こんなの本当にあり得ない……","ENG":"This is ridiculous...","TWN":"這簡直是……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"스승님도 마찬가지죠.","JPN":"師匠も同じじゃないですか。","ENG":"I could say the same about you.","TWN":"師父也一樣啊。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"뭐?","JPN":"なに？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"스승님도 그동안 나유빈에 대해서 물어본 적은 없었죠.","JPN":"師匠だってこれまで、イチノセのことは聞かなかったじゃないですか。","ENG":"You never asked about Na Yubin all these years.","TWN":"師父也從來沒有問過羅瑜斌的消息啊。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"단 한 번도.","JPN":"たった一度も。","ENG":"Not once.","TWN":"連一次也沒有。"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"그날, 한쪽 눈을 잃고 무력화된 제가 그 지옥에서 대체 어떻게 살아 나올 수 있었을까요?","JPN":"あの日、片目を失い力を失くした私が、どうやってあの地獄から生還できたと思いますか？","ENG":"How did you think I managed to make it out of that living hell? I even lost an eye that day.","TWN":"那天，失去了一隻眼睛，無力戰鬥的我，究竟是怎麼從那個地獄中活著出來的？"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"방어선이 완전히 무너지고 전멸하다시피 한 상황에서 들어보지도 못한 고위 침식체에 쫓기면서까지.......","JPN":"防衛線が完全に崩れ、全滅に近い状況で、聞いたこともない高位侵食体に追われていたのに……","ENG":"Our line of defense was completely broken, and there was that high-ranking C.O. we'd never even heard about before...","TWN":"在防禦線完全崩潰、幾乎全軍覆沒的情況下，甚至還被從未聽說過的高等侵蝕體追殺……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"대체 어떻게, 극소수의 인원이나마 살아남을 수 있었는지.......","JPN":"ほんの一握りの人数ではありましたが、どうやって生き残れたのか……","ENG":"But against all odds, a handful of us managed to survive.","TWN":"即使只有極少數人活了下來，但這到底是如何做到的……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"PROLOGUE_02","slots":{"L":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};